const ALLOWED_PROTOCOLS = ['http:', 'https:'];
const BLOCKED_HOSTS = [
  'metadata.google.internal',
  'metadata.google.com',
  '169.254.169.254',
  '169.254.170.2',
  'fd00:ec2::254',
  '[fd00:ec2::254]',
];
const BLOCKED_IP_RANGES = [
  /^127\./,
  /^10\./,
  /^172\.(1[6-9]|2[0-9]|3[01])\./,
  /^192\.168\./,
  /^0\./,
  /^169\.254\./,
  /^fc00:/i,
  /^fd00:/i,
  /^fe80:/i,
  /^::1$/,
  /^::$/,
  /^100\.(6[4-9]|[7-9][0-9]|1[01][0-9]|12[0-7])\./,
];
const REQUEST_TIMEOUT = 10000;
const MAX_RESPONSE_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'HEAD'];

function isBlockedHost(hostname) {
  const normalizedHost = hostname.toLowerCase().replace(/\.$/, '');

  if (BLOCKED_HOSTS.includes(normalizedHost)) {
    return true;
  }

  for (const pattern of BLOCKED_IP_RANGES) {
    if (pattern.test(normalizedHost)) {
      return true;
    }
  }

  return false;
}

function validateUrl(urlString) {
  let parsed;
  try {
    parsed = new URL(urlString);
  } catch (e) {
    return { valid: false, error: 'Invalid URL format' };
  }

  if (!ALLOWED_PROTOCOLS.includes(parsed.protocol)) {
    return { valid: false, error: `Protocol not allowed: ${parsed.protocol}` };
  }

  if (parsed.username || parsed.password) {
    return { valid: false, error: 'URLs with credentials are not allowed' };
  }

  const hostname = parsed.hostname.replace(/^\[|\]$/g, '');

  if (isBlockedHost(hostname)) {
    return { valid: false, error: 'Access to internal/private network addresses is forbidden' };
  }

  return { valid: true, parsed };
}

async function resolveAndValidate(hostname) {
  const dns = require('dns').promises;
  try {
    const addresses = await dns.resolve4(hostname).catch(() => []);
    const addresses6 = await dns.resolve6(hostname).catch(() => []);
    const allAddresses = [...addresses, ...addresses6];

    for (const addr of allAddresses) {
      if (isBlockedHost(addr)) {
        return { safe: false, error: 'URL resolves to a blocked internal address' };
      }
    }
    return { safe: true };
  } catch (e) {
    return { safe: true };
  }
}

const STRIPPED_REQUEST_HEADERS = [
  'host',
  'cookie',
  'authorization',
  'proxy-authorization',
  'x-forwarded-for',
  'x-real-ip',
  'cf-connecting-ip',
];

const STRIPPED_RESPONSE_HEADERS = [
  'set-cookie',
  'transfer-encoding',
];

function filterHeaders(headers, strippedList) {
  const filtered = {};
  for (const [key, value] of Object.entries(headers)) {
    if (!strippedList.includes(key.toLowerCase())) {
      filtered[key] = value;
    }
  }
  return filtered;
}

app.all('/proxy', async (req, res) => {
  const targetUrl = req.query.url || req.body?.url;

  if (!targetUrl) {
    return res.status(400).json({ error: 'Missing required parameter: url' });
  }

  const method = (req.query.method || req.body?.method || 'GET').toUpperCase();
  if (!ALLOWED_METHODS.includes(method)) {
    return res.status(400).json({ error: `HTTP method not allowed: ${method}` });
  }

  const validation = validateUrl(targetUrl);
  if (!validation.valid) {
    return res.status(400).json({ error: validation.error });
  }

  const dnsCheck = await resolveAndValidate(validation.parsed.hostname);
  if (!dnsCheck.safe) {
    return res.status(403).json({ error: dnsCheck.error });
  }

  const forwardHeaders = filterHeaders(req.headers, STRIPPED_REQUEST_HEADERS);

  const customHeaders = req.body?.headers || {};
  for (const [key, value] of Object.entries(customHeaders)) {
    if (!STRIPPED_REQUEST_HEADERS.includes(key.toLowerCase())) {
      forwardHeaders[key] = value;
    }
  }

  let body = undefined;
  if (['POST', 'PUT', 'PATCH'].includes(method) && req.body?.body !== undefined) {
    body = typeof req.body.body === 'string' ? req.body.body : JSON.stringify(req.body.body);
  }

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT);

  try {
    const fetchOptions = {
      method,
      headers: forwardHeaders,
      signal: controller.signal,
      redirect: 'follow',
    };

    if (body !== undefined) {
      fetchOptions.body = body;
    }

    const response = await fetch(targetUrl, fetchOptions);
    clearTimeout(timeout);

    const contentLength = parseInt(response.headers.get('content-length') || '0', 10);
    if (contentLength > MAX_RESPONSE_SIZE) {
      return res.status(502).json({ error: 'Response too large' });
    }

    const responseUrl = response.url || targetUrl;
    const redirectValidation = validateUrl(responseUrl);
    if (!redirectValidation.valid) {
      return res.status(403).json({ error: 'Redirect led to a blocked URL' });
    }
    const redirectDns = await resolveAndValidate(redirectValidation.parsed.hostname);
    if (!redirectDns.safe) {
      return res.status(403).json({ error: 'Redirect resolved to a blocked internal address' });
    }

    const responseHeaders = {};
    response.headers.forEach((value, key) => {
      if (!STRIPPED_RESPONSE_HEADERS.includes(key.toLowerCase())) {
        responseHeaders[key] = value;
      }
    });

    const chunks = [];
    let totalSize = 0;
    const reader = response.body?.getReader();

    if (reader) {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        totalSize += value.length;
        if (totalSize > MAX_RESPONSE_SIZE) {
          reader.cancel();
          return res.status(502).json({ error: 'Response too large' });
        }
        chunks.push(value);
      }
    }

    const buffer = Buffer.concat(chunks);

    res.status(response.status);
    for (const [key, value] of Object.entries(responseHeaders)) {
      res.setHeader(key, value);
    }
    res.setHeader('X-Proxy-Status', response.status);
    res.setHeader('X-Proxy-Url', targetUrl);

    res.send(buffer);
  } catch (err) {
    clearTimeout(timeout);

    if (err.name === 'AbortError') {
      return res.status(504).json({ error: 'Request to target URL timed out' });
    }

    console.error('Proxy error:', err.message);
    return res.status(502).json({ error: 'Failed to fetch from target URL', detail: err.message });
  }
});

